code = """import pandas as pd
import json

business_names_data = locals()['var_function-call-12976435802148334647']
reviews_data = locals()['var_function-call-2568453529529275963']

df_business = pd.DataFrame(business_names_data)
df_reviews = pd.DataFrame(reviews_data)
df_reviews['rating'] = df_reviews['rating'].astype(int)

# Calculate average rating for each business
avg_ratings = df_reviews.groupby('gmap_id')['rating'].mean().reset_index()
avg_ratings.rename(columns={'rating': 'average_rating'}, inplace=True)

# Merge with business names
merged_df = pd.merge(df_business, avg_ratings, on='gmap_id')

# Filter for businesses with average rating of at least 4.0
filtered_businesses = merged_df[merged_df['average_rating'] >= 4.0]

# Format the output
result = filtered_businesses[['name', 'average_rating']].to_dict(orient='records')

print("__RESULT__:")
print(json.dumps(result))"""

